const changes = $input.first().json.changes ?? [];

const EMOJI = { connected: '🤝', replied: '💬', declined: '❌' };
const COLOR = { connected: 5763719, replied: 3447003, declined: 15158332 };

const embeds = changes.map(c => ({
  color: COLOR[c.event] ?? 9807270,
  author: { name: c.campaign_name ?? 'Lead Agents' },
  title: `${EMOJI[c.event] ?? '•'} ${c.person_name}`,
  description: [
    c.title ? `*${c.title}*` : null,
    c.company_name ? `🏢 ${c.company_name}` : null,
    c.event === 'connected' ? 'Prihvatio/la konekciju na LinkedIn-u.' : null,
    c.event === 'replied'   ? '💡 Odgovorio/la — odgovori što pre!' : null,
    c.event === 'declined'  ? 'Odbio/la konekciju.' : null,
  ].filter(Boolean).join('\n'),
  url: c.linkedin_url,
  footer: { text: `Lead Agents OS · ${new Date().toLocaleString('sr-Latn-RS')}` },
}));

// Discord allows max 10 embeds per message
const chunks = [];
for (let i = 0; i < embeds.length; i += 10) chunks.push(embeds.slice(i, i + 10));

return chunks.map((group, i) => ({
  json: {
    discord_payload: {
      username: 'Lead Agents OS',
      embeds: group,
    },
    changes,
    chunk_index: i,
  }
}));

// Flatten changes into individual items for Attio (skip declined)
const changes = $input.first().json.changes ?? [];
return changes
  .filter(c => c.event !== 'declined')
  .map(c => ({ json: c }));

